6) Add these two new methods on Cache (anywhere in the class, e.g. right after __init__):
    def set_compression(self, compress: Optional[str] = None) -> None:
        """Dynamically change the on-disk compression codec for future cache writes."""
        if compress not in (None, "gzip", "zlib"):
            raise ValueError(f"Unsupported cache compression codec: {compress!r}. Expected 'gzip', 'zlib', or None.")
        self.compress = compress

    def _encode_for_disk(self, value: Any) -> bytes:
        codec = _CODEC_NAME_TO_ID[self.compress]
        payload = cloudpickle.dumps(value)
        compress_fn = _COMPRESS_FUNCS.get(codec)
        if compress_fn is not None:
            payload = compress_fn(payload)
        return _CACHE_MAGIC + bytes([codec]) + payload

    @staticmethod
    def _decode_from_disk(blob: Any) -> Any:
        if not isinstance(blob, (bytes, bytearray)) or bytes(blob[:4]) != _CACHE_MAGIC:
            return blob
        codec = blob[4]
        payload = bytes(blob[5:])
        decompress_fn = _DECOMPRESS_FUNCS.get(codec)
        if decompress_fn is not None:
            payload = decompress_fn(payload)
        return cloudpickle.loads(payload)

